#ifndef RMSNORM_H2048_KERNEL_H
#define RMSNORM_H2048_KERNEL_H

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <torch/extension.h>
#include <cstdint>

#ifndef HIDDEN_SIZE
#define HIDDEN_SIZE 2048
#endif

// Host-side CUDA kernel launcher declaration
void rmsnorm_h2048_cuda(const __nv_bfloat16* hidden_states,
                        const __nv_bfloat16* weight,
                        __nv_bfloat16* output,
                        int batch_size,
                        cudaStream_t stream);

// PyTorch extension entrypoint
torch::Tensor run(torch::Tensor hidden_states, torch::Tensor weight);

#endif // RMSNORM_H2048_KERNEL_H

#include "kernel.h"
#include <ATen/cuda/CUDAContext.h>
#include <cuda_bf16.h>
#include <cstdio>
#include <cstdint>

static_assert(HIDDEN_SIZE == 2048, "This kernel is specialized for HIDDEN_SIZE = 2048");

#define CUDA_CHECK(err) \
  do { \
    cudaError_t err_ = (err); \
    if (err_ != cudaSuccess) { \
      printf("CUDA Error %s at %s:%d\n", cudaGetErrorString(err_), __FILE__, __LINE__); \
    } \
  } while (0)

constexpr float EPS = 1e-6f;

__forceinline__ __device__ float warp_reduce_sum(float val) {
  unsigned mask = 0xffffffffu;
  val += __shfl_down_sync(mask, val, 16);
  val += __shfl_down_sync(mask, val, 8);
  val += __shfl_down_sync(mask, val, 4);
  val += __shfl_down_sync(mask, val, 2);
  val += __shfl_down_sync(mask, val, 1);
  return val;
}

// Launch bounds tuned for Ampere (e.g., A800)
template<int BlockThreads>
__launch_bounds__(BlockThreads, 4)
__global__ void rmsnorm_h2048_kernel(const __nv_bfloat16* __restrict__ hidden_states,
                                     const __nv_bfloat16* __restrict__ weight,
                                     __nv_bfloat16* __restrict__ output,
                                     int batch_size) {
  const int row = blockIdx.x;
  if (row >= batch_size) return;

  // Shared memory to store one row of inputs in FP32 for reuse
  __shared__ float s_x[HIDDEN_SIZE];
  // Shared memory for warp partial sums (max 32 warps per block)
  __shared__ float warp_sums[32];

  const __nv_bfloat16* __restrict__ row_in = hidden_states + static_cast<size_t>(row) * HIDDEN_SIZE;
  __nv_bfloat16* __restrict__ row_out = output + static_cast<size_t>(row) * HIDDEN_SIZE;

  float sumsq = 0.f;

  // Load and accumulate sum of squares in FP32
#pragma unroll 8
  for (int i = threadIdx.x; i < HIDDEN_SIZE; i += BlockThreads) {
    float x = __bfloat162float(row_in[i]);
    s_x[i] = x;
    sumsq = fmaf(x, x, sumsq);
  }

  // Intra-warp reduction
  sumsq = warp_reduce_sum(sumsq);

  const int lane = threadIdx.x & 31;
  const int warp_id = threadIdx.x >> 5;
  const int num_warps = BlockThreads >> 5;

  if (lane == 0) {
    warp_sums[warp_id] = sumsq;
  }
  __syncthreads();

  // Reduce warp partials using the first warp
  if (warp_id == 0) {
    float v = (lane < num_warps) ? warp_sums[lane] : 0.f;
    v = warp_reduce_sum(v);
    if (lane == 0) {
      warp_sums[0] = v;
    }
  }
  __syncthreads();

  const float total = warp_sums[0];
  const float mean = total / static_cast<float>(HIDDEN_SIZE);
  const float inv_rms = rsqrtf(mean + EPS);

  // Scale and write back
#pragma unroll 8
  for (int i = threadIdx.x; i < HIDDEN_SIZE; i += BlockThreads) {
    float w = __bfloat162float(weight[i]);
    float y = s_x[i] * inv_rms * w;
    row_out[i] = __float2bfloat16_rn(y);
  }
}

void rmsnorm_h2048_cuda(const __nv_bfloat16* hidden_states,
                        const __nv_bfloat16* weight,
                        __nv_bfloat16* output,
                        int batch_size,
                        cudaStream_t stream) {
  if (batch_size <= 0) return;

  constexpr int threads = 256;
  const dim3 grid(batch_size);
  const dim3 block(threads);

  rmsnorm_h2048_kernel<threads><<<grid, block, 0, stream>>>(
      hidden_states, weight, output, batch_size);

  CUDA_CHECK(cudaGetLastError());
}

#include "kernel.h"

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_bf16.h>
#include <stdexcept>
#include <string>

static void check_inputs(const torch::Tensor& hidden_states,
                         const torch::Tensor& weight) {
  if (!hidden_states.defined() || !weight.defined()) {
    throw std::invalid_argument("hidden_states and weight must be defined tensors");
  }
  if (!hidden_states.device().is_cuda() || !weight.device().is_cuda()) {
    throw std::invalid_argument("hidden_states and weight must be CUDA tensors");
  }
  if (hidden_states.scalar_type() != torch::kBFloat16) {
    throw std::invalid_argument("hidden_states must be of dtype torch.bfloat16");
  }
  if (weight.scalar_type() != torch::kBFloat16) {
    throw std::invalid_argument("weight must be of dtype torch.bfloat16");
  }
  if (hidden_states.dim() != 2) {
    throw std::invalid_argument("hidden_states must be 2D [batch_size, hidden_size]");
  }
  if (weight.dim() != 1) {
    throw std::invalid_argument("weight must be 1D [hidden_size]");
  }
  const auto hidden_size = hidden_states.size(1);
  if (hidden_size != HIDDEN_SIZE) {
    throw std::invalid_argument("hidden_size must be exactly 2048");
  }
  if (weight.size(0) != HIDDEN_SIZE) {
    throw std::invalid_argument("weight size must be exactly 2048");
  }
  if (!hidden_states.is_contiguous()) {
    throw std::invalid_argument("hidden_states must be contiguous");
  }
  if (!weight.is_contiguous()) {
    throw std::invalid_argument("weight must be contiguous");
  }
}

torch::Tensor run(torch::Tensor hidden_states, torch::Tensor weight) {
  try {
    check_inputs(hidden_states, weight);
  } catch (const std::exception& e) {
    throw std::runtime_error(std::string("Input validation failed: ") + e.what());
  }

  const int64_t batch_size = hidden_states.size(0);

  torch::Tensor output = torch::empty_like(hidden_states, hidden_states.options());

  const __nv_bfloat16* hidden_ptr =
      reinterpret_cast<const __nv_bfloat16*>(hidden_states.data_ptr<at::BFloat16>());
  const __nv_bfloat16* weight_ptr =
      reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr<at::BFloat16>());
  __nv_bfloat16* out_ptr =
      reinterpret_cast<__nv_bfloat16*>(output.data_ptr<at::BFloat16>());

  cudaStream_t stream = at::cuda::getCurrentCUDAStream();

  rmsnorm_h2048_cuda(hidden_ptr, weight_ptr, out_ptr, static_cast<int>(batch_size), stream);

  cudaError_t err_sync = cudaStreamSynchronize(stream);
  if (err_sync != cudaSuccess) {
    throw std::runtime_error(std::string("CUDA stream sync failed: ") + cudaGetErrorString(err_sync));
  }
  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    throw std::runtime_error(std::string("CUDA kernel launch failed: ") + cudaGetErrorString(err));
  }

  return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function",
        pybind11::arg("hidden_states"),
        pybind11::arg("weight"));
}
